import{_ as a,c as i,o as t,a1 as n}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Plataformas e Integración: Características de Terminal en macOS, Windows y Linux | opencode-notify","description":"Aprende las diferencias de funcionalidad de opencode-notify en macOS, Windows y Linux, domina el soporte de terminales (37+ emuladores), detección de enfoque, clic para enfocar y características de plataforma como sonidos personalizados. Este capítulo incluye comparación de funcionalidades, mecanismos de detección de terminal y guías de configuración para optimizar tu experiencia de notificaciones según tu sistema operativo y tipo de terminal.","frontmatter":{"title":"Plataformas e Integración: Características de Terminal en macOS, Windows y Linux | opencode-notify","sidebarTitle":"Adapta tu Plataforma","subtitle":"Plataformas e Integración","description":"Aprende las diferencias de funcionalidad de opencode-notify en macOS, Windows y Linux, domina el soporte de terminales (37+ emuladores), detección de enfoque, clic para enfocar y características de plataforma como sonidos personalizados. Este capítulo incluye comparación de funcionalidades, mecanismos de detección de terminal y guías de configuración para optimizar tu experiencia de notificaciones según tu sistema operativo y tipo de terminal.","tags":["Características de Plataforma","Soporte de Terminal","Compatibilidad del Sistema"],"prerequisite":["start-quick-start","start-how-it-works"],"order":2},"headers":[],"relativePath":"es/kdcokenny/opencode-notify/platforms/index.md","filePath":"es/kdcokenny/opencode-notify/platforms/index.md"}'),o={name:"es/kdcokenny/opencode-notify/platforms/index.md"};function d(r,e,s,c,l,m){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="plataformas-e-integracion" tabindex="-1">Plataformas e Integración <a class="header-anchor" href="#plataformas-e-integracion" aria-label="Permalink to &quot;Plataformas e Integración&quot;">​</a></h1><p>Este capítulo te ayuda a comprender las diferencias de funcionalidad de opencode-notify en diferentes sistemas operativos, dominar las configuraciones específicas de plataforma y cómo hacer que tu terminal funcione de manera óptima.</p><h2 id="ruta-de-aprendizaje" tabindex="-1">Ruta de Aprendizaje <a class="header-anchor" href="#ruta-de-aprendizaje" aria-label="Permalink to &quot;Ruta de Aprendizaje&quot;">​</a></h2><h3 id="_1-caracteristicas-de-macos" tabindex="-1">1. <a href="./../macos/">Características de macOS</a> <a class="header-anchor" href="#_1-caracteristicas-de-macos" aria-label="Permalink to &quot;1. [Características de macOS](../macos/)&quot;">​</a></h3><p>Conoce las funciones avanzadas en macOS, incluyendo detección inteligente de enfoque, clic en notificación para enfocar y sonidos personalizados.</p><ul><li>Detección de enfoque: Determina automáticamente si la terminal es la ventana activa actual</li><li>Clic para enfocar: Cambia automáticamente a la terminal al hacer clic en la notificación</li><li>Sonidos personalizados: Configura sonidos exclusivos para diferentes eventos</li><li>Soporte para 37+ terminales: Incluyendo Ghostty, iTerm2, terminal integrado de VS Code, etc.</li></ul><h3 id="_2-caracteristicas-de-windows" tabindex="-1">2. <a href="./../windows/">Características de Windows</a> <a class="header-anchor" href="#_2-caracteristicas-de-windows" aria-label="Permalink to &quot;2. [Características de Windows](../windows/)&quot;">​</a></h3><p>Domina las bases de notificaciones y métodos de configuración en la plataforma Windows.</p><ul><li>Notificaciones nativas: Usa el Centro de Notificaciones de Windows 10/11</li><li>Permisos de notificación: Asegúrate de que OpenCode tenga permiso para enviar notificaciones</li><li>Configuración básica: Ubicación del archivo de configuración en entornos Windows</li><li>Notas de limitaciones: La detección de enfoque no está disponible temporalmente en Windows</li></ul><h3 id="_3-caracteristicas-de-linux" tabindex="-1">3. <a href="./../linux/">Características de Linux</a> <a class="header-anchor" href="#_3-caracteristicas-de-linux" aria-label="Permalink to &quot;3. [Características de Linux](../linux/)&quot;">​</a></h3><p>Comprende el mecanismo de notificaciones y la instalación de dependencias en la plataforma Linux.</p><ul><li>Integración con libnotify: Usa notify-send para enviar notificaciones</li><li>Soporte de entornos de escritorio: GNOME, KDE Plasma, XFCE y otros entornos principales</li><li>Instalación de dependencias: Comandos de instalación para diferentes distribuciones</li><li>Notas de limitaciones: La detección de enfoque no está disponible temporalmente en Linux</li></ul><h3 id="_4-terminales-soportados" tabindex="-1">4. <a href="./../terminals/">Terminales Soportados</a> <a class="header-anchor" href="#_4-terminales-soportados" aria-label="Permalink to &quot;4. [Terminales Soportados](../terminals/)&quot;">​</a></h3><p>Consulta todos los 37+ emuladores de terminal soportados y comprende el mecanismo de detección automática.</p><ul><li>Detección de terminal: Cómo identificar automáticamente tu tipo de terminal</li><li>Lista de terminales: Lista completa de terminales soportados</li><li>Configuración manual: Cómo especificar manualmente cuando la detección automática falla</li><li>Terminales especiales: Manejo de terminales integrados de VS Code y sesiones SSH remotas</li></ul><h2 id="prerrequisitos" tabindex="-1">Prerrequisitos <a class="header-anchor" href="#prerrequisitos" aria-label="Permalink to &quot;Prerrequisitos&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Antes de aprender este capítulo, asegúrate de haber completado</p><ul><li>✅ <strong><a href="./../../start/quick-start/">Inicio Rápido</a></strong>: Instalación de opencode-notify completada</li><li>✅ <strong><a href="./../../start/how-it-works/">Cómo Funciona</a></strong>: Comprender los cuatro tipos de notificación y el mecanismo de filtrado inteligente</li></ul></div><h2 id="recomendaciones-de-seleccion-de-plataforma" tabindex="-1">Recomendaciones de Selección de Plataforma <a class="header-anchor" href="#recomendaciones-de-seleccion-de-plataforma" aria-label="Permalink to &quot;Recomendaciones de Selección de Plataforma&quot;">​</a></h2><p>Selecciona el capítulo correspondiente según tu sistema operativo:</p><table tabindex="0"><thead><tr><th>Sistema Operativo</th><th>Orden de Aprendizaje Recomendado</th><th>Funciones Principales</th></tr></thead><tbody><tr><td><strong>macOS</strong></td><td>1. Características de macOS → 4. Terminales Soportados</td><td>Detección de enfoque, clic para enfocar, sonidos personalizados</td></tr><tr><td><strong>Windows</strong></td><td>2. Características de Windows → 4. Terminales Soportados</td><td>Notificaciones nativas, configuración básica</td></tr><tr><td><strong>Linux</strong></td><td>3. Características de Linux → 4. Terminales Soportados</td><td>Integración con libnotify, instalación de dependencias</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Recomendación General</p><p>Independientemente de la plataforma que uses, la lección 4 &quot;Terminales Soportados&quot; vale la pena aprender, ya que te ayuda a comprender el mecanismo de detección de terminales y resolver problemas de configuración.</p></div><h2 id="tabla-comparativa-de-funciones" tabindex="-1">Tabla Comparativa de Funciones <a class="header-anchor" href="#tabla-comparativa-de-funciones" aria-label="Permalink to &quot;Tabla Comparativa de Funciones&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Función</th><th>macOS</th><th>Windows</th><th>Linux</th></tr></thead><tbody><tr><td>Notificaciones Nativas</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Detección de Enfoque de Terminal</td><td>✅</td><td>❌</td><td>❌</td></tr><tr><td>Clic en Notificación para Enfocar</td><td>✅</td><td>❌</td><td>❌</td></tr><tr><td>Sonidos Personalizados</td><td>✅</td><td>✅</td><td>✅ (Parcial)</td></tr><tr><td>Períodos de Silencio</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Verificación de Sesión Padre</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Soporte para 37+ Terminales</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Detección Automática de Terminal</td><td>✅</td><td>✅</td><td>✅</td></tr></tbody></table><h2 id="siguientes-pasos" tabindex="-1">Siguientes Pasos <a class="header-anchor" href="#siguientes-pasos" aria-label="Permalink to &quot;Siguientes Pasos&quot;">​</a></h2><p>Al completar este capítulo, comprenderás las diferencias de funcionalidad y métodos de configuración en diferentes plataformas.</p><p>Se recomienda continuar aprendiendo:</p><h3 id="configuracion-avanzada" tabindex="-1"><a href="./../../advanced/config-reference/">Configuración Avanzada</a> <a class="header-anchor" href="#configuracion-avanzada" aria-label="Permalink to &quot;[Configuración Avanzada](../../advanced/config-reference/)&quot;">​</a></h3><p>Profundiza en todas las opciones del archivo de configuración y domina técnicas de configuración avanzada.</p><ul><li>Referencia completa de configuración: Descripción detallada de todas las opciones</li><li>Explicación detallada de períodos de silencio: Cómo configurar y su funcionamiento</li><li>Principio de detección de terminal: Mecanismo interno de detección automática</li><li>Uso avanzado: Consejos de configuración y mejores prácticas</li></ul><h3 id="solucion-de-problemas" tabindex="-1"><a href="./../../faq/troubleshooting/">Solución de Problemas</a> <a class="header-anchor" href="#solucion-de-problemas" aria-label="Permalink to &quot;[Solución de Problemas](../../faq/troubleshooting/)&quot;">​</a></h3><p>Consulta soluciones para problemas comunes cuando encuentres dificultades.</p><ul><li>Notificaciones no se muestran: Problemas de permisos y configuración del sistema</li><li>Falla en detección de enfoque: Configuración de terminal y mecanismo de detección</li><li>Errores de configuración: Formato del archivo de configuración y descripción de campos</li><li>Problemas de sonido: Configuración de sonido y compatibilidad del sistema</li></ul><div class="info custom-block"><p class="custom-block-title">Recomendación de Ruta de Aprendizaje</p><p>Si estás comenzando a usar la herramienta, se recomienda seguir el orden <strong>Capítulos de Plataforma → Configuración Avanzada → Solución de Problemas</strong>. Si encuentras un problema específico, puedes ir directamente al capítulo de solución de problemas.</p></div>',33)])])}const f=a(o,[["render",d]]);export{p as __pageData,f as default};
